import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Validate user input length
        if (userInput.length() > 10) {
            System.out.println("Input string is too long. Please enter a string with length <= 10.");
            return;
        }

        // Use StringBuilder to handle variable length input
        StringBuilder buffer = new StringBuilder(userInput);

        System.out.println("Copied string: " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
